import {withable} from "@hoge1e3/withable";
import * as assert from "assert";
export async function main(){
  const p=withable({
    x:3, y:5,
    toString(){
      return `(${this.x},${this.y})`;
    }
  });
  const p2=p.with({x:6});
  const p3=p2.with({y:60});
  this.echo(p+"");
  this.echo(p2+"");
  this.echo(p3+"");
}    
